query:
-- 1. 查询测试城市A的ID
SELECT id FROM cities WHERE name = '测试城市A';

-- 2. 查询测试合伙人A的userId和partnerId
SELECT u.id as userId, p.id as partnerId 
FROM users u
LEFT JOIN partners p ON u.id = p.userId
WHERE u.phone = '18800000001';

-- 3. 删除测试合伙人A的partner_cities记录
DELETE FROM partner_cities 
WHERE partnerId IN (
  SELECT p.id FROM partners p
  JOIN users u ON p.userId = u.id
  WHERE u.phone = '18800000001'
);

-- 4. 删除测试合伙人A的partners记录
DELETE FROM partners 
WHERE userId IN (
  SELECT id FROM users WHERE phone = '18800000001'
);

-- 5. 删除测试合伙人A的user_role_cities记录
DELETE FROM user_role_cities 
WHERE userId IN (
  SELECT id FROM users WHERE phone = '18800000001'
);

-- 6. 删除测试合伙人A的users记录
DELETE FROM users WHERE phone = '18800000001';

-- 7. 删除测试城市A的cities记录
DELETE FROM cities WHERE name = '测试城市A';

-- 8. 验证删除结果
SELECT '测试数据已删除' as result;

